{
  "lean_declaration": "theorem partition_weakly_decreasing_finite {n : ℕ} (p : Nat.Partition n) : Antitone p.parts ∧ (∀ᶠ i in Filter.cofinite, p.parts i = 0) := by\n  exact ⟨p.parts_anti, p.parts_finite⟩",
  "declaration_name": "partition_weakly_decreasing_finite",
  "used_context": [
    "Nat.Partition is a type family parameterized by ℕ",
    "for p : Nat.Partition n, p.parts is the sequence of parts",
    "p.parts_anti : Antitone p.parts",
    "p.parts_finite : ∀ᶠ i in Filter.cofinite, p.parts i = 0"
  ],
  "notes": [
    "Added explicit n parameter because Nat.Partition is a type family expecting a sum."
  ]
}
